struct VoidFunctorVoid
{
  VoidFunctorVoid()
  {
    ++mTotalInstanceCount;
    ++mCurrentInstanceCount;
  }

  VoidFunctorVoid(const VoidFunctorVoid& copyMe)
  {
    ++mTotalInstanceCount;
    ++mCurrentInstanceCount;
  }

  ~VoidFunctorVoid()
  {
    --mCurrentInstanceCount;
  }

  void operator()()
  {
    ++mCallbackCount;
  }

  static int mTotalInstanceCount;
  static int mCurrentInstanceCount;
  static int mCallbackCount;
};

